INSERT INTO decks (id, title, description)
INSERT INTO cards (id, deck_id, question, answer, position)
VALUES
('js-001', 'js-basics', 'Что такое JavaScript?', 'JavaScript - это язык программирования, который используется для создания интерактивной логики на веб-страницах, серверных приложений и других программных систем.', 1),
('js-002', 'js-basics', 'Что такое переменная?', 'Переменная - это именованная область памяти, в которой хранится значение. В JavaScript переменные объявляются с помощью let, const или var.', 2),
('js-003', 'js-basics', 'Чем let отличается от const?', 'let позволяет присваивать переменной новое значение, а const запрещает повторное присваивание. При этом объект, записанный в const, может сохранять изменяемые свойства.', 3),
('js-004', 'js-basics', 'Что такое тип данных?', 'Тип данных определяет, какого рода значение хранится в переменной и какие операции с ним возможны. Например: string, number, boolean, object, undefined, null, symbol, bigint.', 4),
('js-005', 'js-basics', 'Что такое функция?', 'Функция - это блок кода, который можно вызвать по имени или через ссылку. Она может принимать параметры, выполнять действия и возвращать результат.', 5),
('js-006', 'js-basics', 'Что такое область видимости?', 'Область видимости определяет, из какой части программы доступна переменная или функция. В JavaScript есть глобальная, функциональная и блочная области видимости.', 6),
('js-007', 'js-basics', 'Что такое замыкание?', 'Замыкание - это способность функции запоминать переменные из внешней области видимости даже после завершения выполнения этой внешней функции.', 7),
('js-008', 'js-basics', 'Что такое объект?', 'Объект - это структура данных, которая хранит свойства в формате ключ-значение. Значениями могут быть данные или функции.', 8),
('js-009', 'js-basics', 'Что такое массив?', 'Массив - это упорядоченная коллекция значений, доступ к которым обычно осуществляется по числовому индексу.', 9),
('js-010', 'js-basics', 'Что такое DOM?', 'DOM - это объектная модель документа, через которую JavaScript может читать и изменять структуру, содержимое и стили HTML-страницы.', 10),
('js-011', 'js-basics', 'Что такое событие?', 'Событие - это сигнал о действии пользователя или браузера, например клик, ввод текста, загрузка страницы или отправка формы.', 11),
('js-012', 'js-basics', 'Что такое Promise?', 'Promise - это объект, представляющий результат асинхронной операции. Он может находиться в состояниях pending, fulfilled или rejected.', 12),
('js-013', 'js-basics', 'Что делают async и await?', 'async объявляет функцию асинхронной, а await приостанавливает выполнение этой функции до завершения Promise и возвращает его результат.', 13),
('js-014', 'js-basics', 'Что такое callback?', 'Callback - это функция, переданная другой функции как аргумент, чтобы быть вызванной позже при наступлении нужного момента.', 14),
('js-015', 'js-basics', 'Что такое JSON?', 'JSON - это текстовый формат обмена данными, основанный на парах ключ-значение и массивах. В JavaScript его можно обрабатывать через JSON.parse и JSON.stringify.', 15),
('js-016', 'js-basics', 'Что такое строгий режим?', 'Строгий режим включается директивой use strict и заставляет JavaScript строже проверять код, запрещая ряд небезопасных или устаревших возможностей.', 16),
('js-017', 'js-basics', 'Что такое прототип?', 'Прототип - это объект, от которого другой объект может наследовать свойства и методы. Прототипы лежат в основе наследования в JavaScript.', 17),
('js-018', 'js-basics', 'Что такое this?', 'this - это специальное значение, которое обычно указывает на объект, в контексте которого вызвана функция. Его значение зависит от способа вызова.', 18),
('js-019', 'js-basics', 'Что такое модуль?', 'Модуль - это отдельный файл или часть программы, которая экспортирует и импортирует значения, позволяя разделять код на независимые части.', 19),
('js-020', 'js-basics', 'Что такое fetch?', 'fetch - это браузерный API для выполнения HTTP-запросов. Он возвращает Promise и часто используется для получения данных с backend.', 20);
